INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES ("", 0.2, 312002, "nop_talk_joy1", 1, "", 3, 312, "", "", 101831);
