INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 0, 505013, "ミヤコさん、クリスマスにたくさん\n食べたじゃありませんか……", 6, 0.5, 11, 505, 1, 0, 103111);
