INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 0, 506013, "クリスティーナ！\nあなたはいったいどの面下げて\n私たちの前に……", 8, 0.5, 11, 506, 1, 0, 103731);
INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES ("", 0.2, 506014, "nop_06_tomo_talk_anger", 1, "", 3, 506, "", "", 103731);
