INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 0, 506018, "まあまあ、\nトモちゃんもクリスちゃんも。\nせっかくの新年会なんだから……", 8, 0.5, 11, 506, 1, 0, 104731);
