INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 0, 506023, "そうッス！\n美味しい料理もいっぱいだし、\n楽しまなくっちゃ損ッスよ！", 8, 0.5, 11, 506, 1, 0, 100511);
